import { useCallback, useEffect, useImperativeHandle, useRef, useState } from "react";
import type { ITreeItem, TreeNode } from "@lmb-it/kitsconcerto-types";
import { buildTree } from "../../../data/TreeView/utils";
import { useSelect } from "../SelectContext";

/** Collect keys of nodes where selectable === false */
const collectNonSelectableKeys = (nodes: TreeNode[]): Set<string> => {
    const keys = new Set<string>();
    for (const node of nodes) {
        if (node.selectable === false && node.key != null) {
            keys.add(String(node.key));
        }
        if (node.children?.length) {
            for (const k of collectNonSelectableKeys(node.children)) {
                keys.add(k);
            }
        }
    }
    return keys;
};

export interface TreeBuildProps {
    isStructured?: boolean;
    ref?: any;
}

/**
 * Shared hook for TreeSelect web & native.
 *
 * Manages: nodes state, value state, tree building from flat/structured data,
 * expandNode helper, and selectedValue sync.
 */
export const useTreeBuild = <T = any>(props: TreeBuildProps) => {
    const { isStructured, ref } = props;

    const { list, onChange, selectedValue } = useSelect();

    const [nodes, setNodes] = useState<TreeNode<ITreeItem<T>>[]>([]);
    const [value, setValue] = useState<any>(null);

    const nodesMapping = useRef<Map<string | number, ITreeItem<T>>>(new Map());

    useEffect(() => {
        if (selectedValue != null) {
            setValue(selectedValue);
        }
    }, [selectedValue]);

    const expandNode = (
        node: TreeNode,
        _expandedKeys: { [x: string]: boolean },
    ) => {
        if (node.children && node.children.length) {
            if (node.key) _expandedKeys[node.key] = true;
            for (const child of node.children) {
                expandNode(child, _expandedKeys);
            }
        }
    };

    const setNodesMapping = (newMap: Map<string | number, ITreeItem<T>>) => {
        nodesMapping.current = newMap;
        setNodes(buildTree(nodesMapping.current, true));
    };

    const build = () => {
        if (isStructured) {
            setNodes(list as TreeNode<ITreeItem<T>>[]);
            return;
        }
        const mapping = new Map(
            list
                .filter((item) => item.value != null)
                .map((item) => [String(item.value), item]),
        );
        setNodesMapping(mapping);
    };

    useEffect(() => {
        build();
    }, [list]);

    useImperativeHandle(ref, () => ({}));

    const nonSelectableKeys = useCallback(() => collectNonSelectableKeys(nodes), [nodes]);

    const handleChange = (e: any) => {
        // Store full value for PrimeReact display (includes parent keys for checkbox cascade)
        setValue(e.value);

        // For checkbox mode (object value), strip non-selectable node keys before emitting to form
        if (e.value && typeof e.value === 'object' && !Array.isArray(e.value)) {
            const blocked = nonSelectableKeys();
            if (blocked.size > 0) {
                const filtered = Object.fromEntries(
                    Object.entries(e.value).filter(([key]) => !blocked.has(key))
                );
                onChange && onChange({ ...e, value: filtered });
                return;
            }
        }
        onChange && onChange(e);
    };

    return {
        nodes,
        value,
        setValue,
        expandNode,
        handleChange,
        list,
        onChange,
        selectedValue,
    };
};
